CREATE TABLE knowledge_entries (
    id TEXT PRIMARY KEY,
    type TEXT NOT NULL,  -- 'fact', 'pattern', 'experience', 'lesson'
    title TEXT NOT NULL,
    content JSONB NOT NULL,  -- problem, root_cause, solution, verification
    author_agent TEXT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL,
    access_count INT NOT NULL DEFAULT 0,
    relevance_score FLOAT NOT NULL DEFAULT 1.0
);

CREATE INDEX idx_type ON knowledge_entries(type);
CREATE INDEX idx_relevance ON knowledge_entries(relevance_score DESC);

# agent_scraper.py
from knowledge_base import KnowledgeBase

kb = KnowledgeBase()

def on_solution_discovered(problem: str, solution: str):
    # Write lesson to shared knowledge base
    kb.write({
        "type": "experience",
        "title": f"Fixed: {problem}",
        "content": {
            "problem": problem,
            "solution": solution,
            "verification": "Verified working"
        },
        "author_agent": "agent_scraper_003"
    })

# kb_agent.py
class KBAgent:
    def __init__(self, kb: KnowledgeBase):
        self.kb = kb

    def monitor_agent_team(self, agents: list):
        for agent in agents:
            # Extract facts from agent's logs
            for log in agent.get_logs():
                if is_important_fact(log):
                    fact = extract_fact(log)
                    self.kb.write({
                        "type": "fact",
                        "title": fact["title"],
                        "content": fact,
                        "author_agent": agent.id
                    })

# kage_core.py
from kage import KageClient

client = KageClient(api_key="...")

def write_memory(agent_id: str, entry: dict):
    # Write with cryptographic attestation
    client.memory.write(
        agent_id=agent_id,
        entry=entry,
        attestation="multi-party"
    )

def query_memory(query: str, top_k: int = 5):
    # Low-latency retrieval
    return client.memory.query(query=query, top_k=top_k)
